5	
6	//! Thread Block Cluster Test - Testing Hopper cluster intrinsics (sm_90+)
7	//!
8	//! This example demonstrates:
9	//! - Cluster special registers (`cluster_ctaidX`, `cluster_nctaidX`, etc.)
10	//! - Cluster synchronization (`cluster_sync`)
11	//! - Distributed shared memory (`map_shared_rank`)
12	//!
13	//! **Hardware Requirements:** Hopper (H100, H200) or newer GPUs with sm_90+
14	//!
15	//! Uses unified compilation: single `cargo oxide run cluster`
16	
17	use core::ptr::{addr_of, addr_of_mut};
18	use cuda_device::{DisjointSlice, SharedArray, cluster, cluster_launch, kernel, thread};
19	use cuda_host::cuda_module;
20	
21	// ============================================================================
22	// Test 0: Compile-Time Cluster Configuration with #[cluster(x,y,z)]
23	// ============================================================================
24	#[cuda_module]
25	mod kernels {
26	    use super::*;
27	
28	    /// Test kernel with compile-time cluster configuration.
29	    ///
30	    /// The `#[cluster_launch(4, 1, 1)]` attribute tells the compiler to emit:
31	    /// ```ptx
32	    /// .entry test_cluster_compile_time .reqnctapercluster 4, 1, 1 { ... }
33	    /// ```
34	    #[kernel]
35	    #[cluster_launch(4, 1, 1)]
36	    pub fn test_cluster_compile_time(mut output: DisjointSlice<u32>) {
37	        let tid = thread::threadIdx_x();
38	        let my_rank = cluster::block_rank();
39	        let cluster_size = cluster::cluster_size();
40	
41	        // Write cluster info to output
42	        if tid == 0 {
43	            let idx = my_rank as usize;
44	            if idx < output.len() {
45	                // Encode: high 16 bits = rank, low 16 bits = cluster_size
46	                let value = ((my_rank as u32) << 16) | (cluster_size as u32);
47	                unsafe { *output.get_unchecked_mut(idx) = value };
48	            }
49	        }
50	    }
51	
52	    // ============================================================================
53	    // Test 1: Basic Cluster Intrinsics
54	    // ============================================================================
55	
56	    /// Test kernel for cluster special registers.
57	    #[kernel]
58	    pub fn test_cluster_intrinsics(mut output: DisjointSlice<u32>) {
59	        let tid = thread::threadIdx_x();
60	        let bid = thread::blockIdx_x();
61	
62	        // Offset for this block's output
63	        let base = (bid as usize) * 8;
64	
65	        let value = match tid {
66	            0 => cluster::cluster_ctaidX(),
67	            1 => cluster::cluster_ctaidY(),
68	            2 => cluster::cluster_ctaidZ(),
69	            3 => cluster::cluster_nctaidX(),
70	            4 => cluster::cluster_nctaidY(),
71	            5 => cluster::cluster_nctaidZ(),
72	            6 => cluster::block_rank(),
73	            7 => cluster::cluster_size(),
74	            _ => 0xDEADBEEF,
75	        };
76	
77	        if tid < 8 {
78	            let idx = base + tid as usize;
79	            if idx < output.len() {
80	                unsafe { *output.get_unchecked_mut(idx) = value };
81	            }
82	        }
83	    }
84	
85	    // ============================================================================
86	    // Test 2: Cluster Synchronization
87	    // ============================================================================
88	
89	    /// Test kernel for cluster_sync().
90	    ///
91	    /// `cluster_sync` only has meaning when the kernel actually runs as a
92	    /// thread-block cluster, so this must carry `#[cluster_launch(...)]` like
93	    /// the DSMEM tests below. Without it the grid launches as ordinary blocks,
94	    /// every block is its own size-1 cluster, `block_rank()` is always 0, and
95	    /// only `output[0]` is written.
96	    #[kernel]
97	    #[cluster_launch(4, 1, 1)]
98	    pub fn test_cluster_sync(mut output: DisjointSlice<u32>) {
99	        static mut SHMEM: SharedArray<u32, 1> = SharedArray::UNINIT;
100	
101	        let tid = thread::threadIdx_x();
102	        let my_rank = cluster::block_rank();
103	
104	        // Step 1: Thread 0 writes block's rank to shared memory
105	        if tid == 0 {
106	            unsafe { (addr_of_mut!(SHMEM) as *mut u32).write(my_rank * 100 + 42) };
107	        }
108	        thread::sync_threads();
109	
110	        // Step 2: Synchronize entire cluster
111	        cluster::cluster_sync();
112	
113	        // Step 3: Write result (proves we passed the barrier)
114	        if tid == 0 {
115	            let idx = my_rank as usize;
116	            if idx < output.len() {
117	                let local_value = unsafe { *(addr_of!(SHMEM) as *const u32) };
118	                unsafe { *output.get_unchecked_mut(idx) = local_value };
119	            }
120	        }
121	    }
122	
123	    // ============================================================================
124	    // Test 3: Distributed Shared Memory (Ring Exchange)
125	    // ============================================================================
126	
127	    /// Test kernel for distributed shared memory via dsmem_read_u32().
128	    #[kernel]
129	    #[cluster_launch(4, 1, 1)]
130	    pub fn test_dsmem_ring_exchange(mut output: DisjointSlice<u32>) {
131	        static mut SHMEM: SharedArray<u32, 1> = SharedArray::UNINIT;
132	
133	        let tid = thread::threadIdx_x();
134	        let my_rank = cluster::block_rank();
135	        let cluster_size = cluster::cluster_size();
136	
137	        // Step 1: Each block writes its unique value to shared memory
138	        if tid == 0 {
139	            unsafe { (addr_of_mut!(SHMEM) as *mut u32).write(1000 + my_rank) };
140	        }
141	        thread::sync_threads();
142	
143	        // Step 2: Cluster-wide sync to ensure all blocks have written
144	        cluster::cluster_sync();
145	
146	        // Step 3: Read neighbor's shared memory (ring pattern)
147	        if tid == 0 {
148	            let neighbor_rank = (my_rank + 1) % cluster_size;
149	            let neighbor_value =
150	                unsafe { cluster::dsmem_read_u32(addr_of!(SHMEM) as *const u32, neighbor_rank) };
151	
152	            let idx = my_rank as usize;
153	            if idx < output.len() {
154	                unsafe { *output.get_unchecked_mut(idx) = neighbor_value };
155	            }
156	        }
157	    }
158	
159	    // ============================================================================
160	    // Test 4: Distributed Reduction (All-to-One)
161	    // ============================================================================
162	
163	    /// Test kernel for distributed reduction using DSMEM.
164	    #[kernel]
165	    #[cluster_launch(4, 1, 1)]
166	    pub fn test_dsmem_reduction(mut output: DisjointSlice<u32>) {
167	        static mut LOCAL_VAL: SharedArray<u32, 1> = SharedArray::UNINIT;
168	
169	        let tid = thread::threadIdx_x();
170	        let my_rank = cluster::block_rank();
171	        let cluster_size = cluster::cluster_size();
172	
173	        // Step 1: Each block writes its contribution
174	        if tid == 0 {
175	            unsafe { (addr_of_mut!(LOCAL_VAL) as *mut u32).write((my_rank + 1) * 10) };
176	        }
177	        thread::sync_threads();
178	
179	        // Step 2: Cluster-wide sync
180	        cluster::cluster_sync();
181	
182	        // Step 3: Block 0 reads all blocks' values and sums them
183	        if tid == 0 && my_rank == 0 {
184	            let mut total = unsafe { *(addr_of!(LOCAL_VAL) as *const u32) };
185	
186	            let mut rank = 1u32;
187	            while rank < cluster_size {
188	                total +=
189	                    unsafe { cluster::dsmem_read_u32(addr_of!(LOCAL_VAL) as *const u32, rank) };
190	                rank += 1;
191	            }
192	
193	            if !output.is_empty() {
194	                unsafe { *output.get_unchecked_mut(0) = total };
195	            }
196	        }
197	
198	        // All blocks must stay alive while block 0 reads DSMEM
199	        cluster::cluster_sync();
200	    }
201	}
202	
203	// ============================================================================
204	// HOST CODE
205	// ============================================================================
206	
207	fn main() {
208	    use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
209	
210	    println!("=== Thread Block Cluster Tests (sm_90+) ===\n");
211	
212	    let ctx = CudaContext::new(0).expect("CUDA context");
213	    let stream = ctx.default_stream();
214	
215	    let (major, minor) = ctx.compute_capability().expect("compute capability");
216	    println!("GPU Compute Capability: sm_{}{}", major, minor);
217	
218	    if major < 9 {
219	        println!("\nskipping: Thread Block Clusters require sm_90+ (Hopper)");
220	        println!("  this GPU is sm_{}{}", major, minor);
221	        return;
222	    }
223	
224	    let module = ctx
225	        .load_module_from_file("cluster.ptx")
226	        .expect("Load PTX module");
227	    let module = kernels::from_module(module).expect("Failed to initialize typed CUDA module");
228	
229	    let cluster_size = 4u32;
230	
231	    // ====================================================================
232	    // Test 0: Compile-Time Cluster Config (uses cuLaunchKernelEx)
233	    // ====================================================================
234	
235	    println!("=== Test 0: Compile-Time Cluster Configuration ===\n");
236	
237	    let mut ct_output = DeviceBuffer::<u32>::zeroed(&stream, cluster_size as usize).unwrap();
238	
239	    println!("Launching test_cluster_compile_time via cuLaunchKernelEx");
240	    println!("  Grid: 4x1x1, Block: 32, Cluster: 4x1x1\n");
241	
242	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
243	    unsafe {
244	        module.test_cluster_compile_time(
245	            (stream).as_ref(),
246	            LaunchConfig {
247	                grid_dim: (cluster_size, 1, 1),
248	                block_dim: (32, 1, 1),
249	                shared_mem_bytes: 0,
250	            },
251	            &mut ct_output,
252	        )
253	    }
254	    .expect("Launch compile-time cluster kernel");
255	    stream.synchronize().expect("Synchronize");
256	
257	    let ct_results: Vec<u32> = ct_output.to_host_vec(&stream).unwrap();
258	    println!("Results (each block writes: (rank << 16) | cluster_size):");
259	    for (i, &val) in ct_results.iter().enumerate() {
260	        let rank = val >> 16;
261	        let size = val & 0xFFFF;
262	        println!(
263	            "  Block {}: raw=0x{:08X}, rank={}, cluster_size={}",
264	            i, val, rank, size
265	        );
266	    }
267	
268	    let mut ct_pass = true;
269	    for (i, &val) in ct_results.iter().enumerate() {
270	        let rank = val >> 16;
271	        let size = val & 0xFFFF;
272	        if size != cluster_size || rank != i as u32 {
273	            println!(
274	                "  ❌ Block {} mismatch: expected rank={}, size={}",
275	                i, i, cluster_size
276	            );
277	            ct_pass = false;
278	        }
279	    }
280	    if ct_pass && ct_results.iter().any(|&v| (v & 0xFFFF) == cluster_size) {
281	        println!("✓ Compile-time cluster config test PASSED\n");
282	    } else {
283	        println!(
284	            "⚠ Cluster intrinsics returned defaults (driver may not support .reqnctapercluster)\n"
285	        );
286	    }
287	
288	    // ====================================================================
289	    // Test 1: Cluster Intrinsics
290	    // ====================================================================
291	
292	    println!("=== Test 1: Cluster Intrinsics (no cluster config) ===\n");
293	
294	    let n_blocks = 4u32;
295	    let output_size = (n_blocks * 8) as usize;
